import{_ as o,o as t,c as r,ag as a}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"Sandbox Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"muthr/sandbox-architecture.md","filePath":"muthr/sandbox-architecture.md","lastUpdated":null}'),i={name:"muthr/sandbox-architecture.md"};function n(c,e,s,d,l,u){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="sandbox-architecture" tabindex="-1">Sandbox Architecture <a class="header-anchor" href="#sandbox-architecture" aria-label="Permalink to &quot;Sandbox Architecture&quot;">​</a></h1><p>This is the technical core of muthr.</p><h2 id="per-project-container-mapping" tabindex="-1">Per-project container mapping <a class="header-anchor" href="#per-project-container-mapping" aria-label="Permalink to &quot;Per-project container mapping&quot;">​</a></h2><p>muthr resolves sandbox identity from your current directory relative to <code>workspace_root</code>.</p><ul><li>project dir <code>~/src/homepage</code> -&gt; container <code>muthr-homepage</code></li><li>project dir <code>~/src/muthr</code> -&gt; container <code>muthr-muthr</code></li></ul><p>This keeps isolation boundaries project-scoped by default.</p><h2 id="mount-model" tabindex="-1">Mount model <a class="header-anchor" href="#mount-model" aria-label="Permalink to &quot;Mount model&quot;">​</a></h2><p>Each sandbox mounts the project workspace into the guest path (default <code>/workspace</code>).</p><p>Important consequence:</p><ul><li>only project files are intentionally exposed</li><li>your full host home is not mounted</li></ul><h2 id="runtime-env-contract" tabindex="-1">Runtime env contract <a class="header-anchor" href="#runtime-env-contract" aria-label="Permalink to &quot;Runtime env contract&quot;">​</a></h2><p>Before launching profile workflows, muthr injects an explicit env surface into sandbox sessions:</p><ul><li><code>MUTHR_INFERENCE_URL</code></li><li><code>MUTHR_OPENAI_URL</code></li><li><code>MUTHR_MCP_BRIDGE_URL</code></li><li><code>MUTHR_SEARXNG_URL</code></li><li><code>MUTHR_MODEL_NAME</code></li><li><code>MUTHR_ENGINE_RUNTIME</code></li></ul><p>This contract gives agent runtimes what they need without giving broad host context.</p><h2 id="provision-transport" tabindex="-1">Provision transport <a class="header-anchor" href="#provision-transport" aria-label="Permalink to &quot;Provision transport&quot;">​</a></h2><p>Profile scripts are copied into container <code>/tmp</code> and executed there. muthr validates env values and model names before invocation. Provision library content is hashed into <code>MUTHR_SPECS_REV</code> for reproducibility tracking.</p><h2 id="baseline-hardening-behavior" tabindex="-1">Baseline hardening behavior <a class="header-anchor" href="#baseline-hardening-behavior" aria-label="Permalink to &quot;Baseline hardening behavior&quot;">​</a></h2><p>muthr enforces a baseline setup step for project sandboxes:</p><ul><li>installs required userland tooling (<code>bash</code>, <code>curl</code>, <code>git</code>, <code>nodejs</code>, <code>npm</code>, ...)</li><li>creates/maintains <code>muthr</code> user</li><li>syncs UID/GID with host user when possible</li></ul><p>This avoids file ownership drift on bind mounts and keeps shell ergonomics predictable.</p><h2 id="network-posture" tabindex="-1">Network posture <a class="header-anchor" href="#network-posture" aria-label="Permalink to &quot;Network posture&quot;">​</a></h2><p>Profiles can request restricted network behavior. muthr supports deferred post-provision network isolation (<code>network none</code>) when backend supports container update. If plugin support is missing, muthr emits warning and continues safely.</p><h2 id="audit-logs" tabindex="-1">Audit logs <a class="header-anchor" href="#audit-logs" aria-label="Permalink to &quot;Audit logs&quot;">​</a></h2><p><code>sandbox start</code> and <code>sandbox shell</code> support <code>--audit-log</code> for NDJSON session records including:</p><ul><li>session start/exit timestamps</li><li>command argv</li><li>TTY mode</li><li>runtime env summary</li></ul><p>This is useful for compliance-style local tracing and incident review.</p>',26)])])}const m=o(i,[["render",n]]);export{p as __pageData,m as default};
